+    sign.resize(EVP_MAX_MD_SIZE);
+    std::error_code ec{};
+
+    uint32_t len = 0;
+
+    unsigned char* res = HMAC(Hasher{}(),
+                              key.data(),
+                              key.length(),
+                              reinterpret_cast<const unsigned char*>(data.data()),
+                              data.length(),
+                              reinterpret_cast<unsigned char*>(&sign[0]),
+                              &len);
+    if (!res) {
