+   *
+   *  Exceptions:
+   *    Any allocation failure will result in jwt::MemoryAllocationException
+   *    being thrown.
+   */
+  static verify_result_t
+  verify(const jwt::string_view key, const jwt::string_view head, const jwt::string_view sign);
+
+};
